def _compute_inhibition_percent(
    y_pred: np.ndarray,
    *,
    mode: str,
    control_y: float,
    top: float,
    bottom: float,
) -> np.ndarray | None:
    if mode == "control":
        denom = abs(control_y)
        if denom <= 1e-9:
            return None
        return 100.0 * (control_y - y_pred) / denom

    if mode == "range_norm":
        dyn = top - bottom
        if abs(dyn) <= 1e-9:
            return None
        return 100.0 * (top - y_pred) / dyn

    return None

